import{_ as n,c as t,o as s,a1 as i}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Befehle: Überwachung & Bereinigung | opencode-dynamic-context-pruning","description":"Lernen Sie die 4 DCP-Befehle zur Überwachung und manuellen Bereinigung. /dcp context zeigt die Sitzung, /dcp stats die Statistiken, /dcp sweep löst die manuelle Bereinigung aus.","frontmatter":{"title":"Befehle: Überwachung & Bereinigung | opencode-dynamic-context-pruning","sidebarTitle":"Token überwachen, manuell bereinigen","subtitle":"DCP-Befehlsanleitung: Überwachung und manuelle Bereinigung","description":"Lernen Sie die 4 DCP-Befehle zur Überwachung und manuellen Bereinigung. /dcp context zeigt die Sitzung, /dcp stats die Statistiken, /dcp sweep löst die manuelle Bereinigung aus.","tags":["DCP-Befehle","Token-Überwachung","Manuelle Bereinigung"],"prerequisite":["start-getting-started","platforms-auto-pruning"],"order":3},"headers":[],"relativePath":"de/Opencode-DCP/opencode-dynamic-context-pruning/platforms/commands/index.md","filePath":"de/Opencode-DCP/opencode-dynamic-context-pruning/platforms/commands/index.md"}'),a={name:"de/Opencode-DCP/opencode-dynamic-context-pruning/platforms/commands/index.md"};function r(l,e,o,d,c,p){return s(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="dcp-befehlsanleitung-uberwachung-und-manuelle-bereinigung" tabindex="-1">DCP-Befehlsanleitung: Überwachung und manuelle Bereinigung <a class="header-anchor" href="#dcp-befehlsanleitung-uberwachung-und-manuelle-bereinigung" aria-label="Permalink to &quot;DCP-Befehlsanleitung: Überwachung und manuelle Bereinigung&quot;">​</a></h1><h2 id="was-sie-lernen-werden" tabindex="-1">Was Sie lernen werden <a class="header-anchor" href="#was-sie-lernen-werden" aria-label="Permalink to &quot;Was Sie lernen werden&quot;">​</a></h2><ul><li>Mit <code>/dcp context</code> die Token-Verteilung der aktuellen Sitzung anzeigen</li><li>Mit <code>/dcp stats</code> die kumulierten Bereinigungsstatistiken einsehen</li><li>Mit <code>/dcp sweep [n]</code> die manuelle Bereinigung auslösen</li><li>Den Schutzmechanismus für geschützte Tools und Dateien verstehen</li><li>Die Token-Berechnungsstrategie und Einspareffekte kennenlernen</li></ul><h2 id="ihre-aktuelle-herausforderung" tabindex="-1">Ihre aktuelle Herausforderung <a class="header-anchor" href="#ihre-aktuelle-herausforderung" aria-label="Permalink to &quot;Ihre aktuelle Herausforderung&quot;">​</a></h2><p>In langen Gesprächen steigt der Token-Verbrauch immer schneller, aber Sie wissen nicht:</p><ul><li>Wohin gehen die Token in der aktuellen Sitzung?</li><li>Wie viel hat DCP tatsächlich eingespart?</li><li>Wie können Sie Tool-Ausgaben manuell bereinigen, die nicht mehr benötigt werden?</li><li>Welche Tools sind geschützt und werden nicht bereinigt?</li></ul><p>Ohne diese Fragen zu klären, können Sie die Optimierungseffekte von DCP möglicherweise nicht voll ausschöpfen und könnten in kritischen Momenten wichtige Informationen versehentlich löschen.</p><h2 id="wann-sie-diese-technik-anwenden-sollten" tabindex="-1">Wann Sie diese Technik anwenden sollten <a class="header-anchor" href="#wann-sie-diese-technik-anwenden-sollten" aria-label="Permalink to &quot;Wann Sie diese Technik anwenden sollten&quot;">​</a></h2><p>Wenn Sie:</p><ul><li>Die Token-Zusammensetzung der aktuellen Sitzung verstehen möchten</li><li>Den Gesprächsverlauf schnell bereinigen müssen</li><li>Die Bereinigungseffekte von DCP überprüfen möchten</li><li>Vor dem Start einer neuen Aufgabe eine Kontextbereinigung durchführen möchten</li></ul><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><p>DCP bietet 4 Slash-Befehle, um Token-Nutzung zu überwachen und zu steuern:</p><table tabindex="0"><thead><tr><th>Befehl</th><th>Zweck</th><th>Anwendungsfall</th></tr></thead><tbody><tr><td><code>/dcp</code></td><td>Hilfe anzeigen</td><td>Wenn Sie Befehle vergessen haben</td></tr><tr><td><code>/dcp context</code></td><td>Token-Verteilung der aktuellen Sitzung analysieren</td><td>Kontextzusammensetzung verstehen</td></tr><tr><td><code>/dcp stats</code></td><td>Kumulierte Bereinigungsstatistiken anzeigen</td><td>Langzeiteffekte überprüfen</td></tr><tr><td><code>/dcp sweep [n]</code></td><td>Tools manuell bereinigen</td><td>Kontextgröße schnell reduzieren</td></tr></tbody></table><p><strong>Schutzmechanismus</strong>:</p><p>Alle Bereinigungsoperationen überspringen automatisch:</p><ul><li><strong>Geschützte Tools</strong>: <code>task</code>, <code>todowrite</code>, <code>todoread</code>, <code>discard</code>, <code>extract</code>, <code>batch</code>, <code>write</code>, <code>edit</code>, <code>plan_enter</code>, <code>plan_exit</code></li><li><strong>Geschützte Dateien</strong>: Dateipfade, die den konfigurierten <code>protectedFilePatterns</code> entsprechen</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Die Einstellungen für geschützte Tools und Dateien können über die Konfigurationsdatei angepasst werden. Siehe <a href="./../../start/configuration/">Vollständige Konfiguration</a> für Details.</p></div><h2 id="schritt-fur-schritt-anleitung" tabindex="-1">Schritt-für-Schritt-Anleitung <a class="header-anchor" href="#schritt-fur-schritt-anleitung" aria-label="Permalink to &quot;Schritt-für-Schritt-Anleitung&quot;">​</a></h2><h3 id="schritt-1-hilfeinformationen-anzeigen" tabindex="-1">Schritt 1: Hilfeinformationen anzeigen <a class="header-anchor" href="#schritt-1-hilfeinformationen-anzeigen" aria-label="Permalink to &quot;Schritt 1: Hilfeinformationen anzeigen&quot;">​</a></h3><p>Geben Sie <code>/dcp</code> im OpenCode-Dialogfeld ein.</p><p><strong>Sie sollten sehen</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                      DCP Commands                         │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  /dcp context      Show token usage breakdown for current session</span></span>
<span class="line"><span>  /dcp stats        Show DCP pruning statistics</span></span>
<span class="line"><span>  /dcp sweep [n]    Prune tools since last user message, or last n tools</span></span></code></pre></div><p><strong>Checkpoint ✅</strong>: Bestätigen Sie, dass Sie die Beschreibungen der 3 Unterbefehle sehen.</p><h3 id="schritt-2-token-verteilung-der-aktuellen-sitzung-analysieren" tabindex="-1">Schritt 2: Token-Verteilung der aktuellen Sitzung analysieren <a class="header-anchor" href="#schritt-2-token-verteilung-der-aktuellen-sitzung-analysieren" aria-label="Permalink to &quot;Schritt 2: Token-Verteilung der aktuellen Sitzung analysieren&quot;">​</a></h3><p>Geben Sie <code>/dcp context</code> ein, um die Token-Nutzung der aktuellen Sitzung anzuzeigen.</p><p><strong>Sie sollten sehen</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                  DCP Context Analysis                     │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Session Context Breakdown:</span></span>
<span class="line"><span>────────────────────────────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>System         15.2% │████████████████▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒│  25.1K tokens</span></span>
<span class="line"><span>User            5.1% │████▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒▒│   8.4K tokens</span></span>
<span class="line"><span>Assistant       35.8% │██████████████████████████████████████▒▒▒▒▒▒▒│  59.2K tokens</span></span>
<span class="line"><span>Tools (45)      43.9% │████████████████████████████████████████████████│  72.6K tokens</span></span>
<span class="line"><span></span></span>
<span class="line"><span>────────────────────────────────────────────────────────────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Summary:</span></span>
<span class="line"><span>  Pruned:          12 tools (~15.2K tokens)</span></span>
<span class="line"><span>  Current context: ~165.3K tokens</span></span>
<span class="line"><span>  Without DCP:     ~180.5K tokens</span></span></code></pre></div><p><strong>Token-Kategorien erklärt</strong>:</p><table tabindex="0"><thead><tr><th>Kategorie</th><th>Berechnungsmethode</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>System</strong></td><td><code>firstAssistant.input + cache.read - tokenizer(firstUserMessage)</code></td><td>System-Prompt</td></tr><tr><td><strong>Tools</strong></td><td><code>tokenizer(toolInputs + toolOutputs) - prunedTokens</code></td><td>Tool-Aufrufe (abzüglich bereinigter Teile)</td></tr><tr><td><strong>User</strong></td><td><code>tokenizer(all user messages)</code></td><td>Alle Benutzernachrichten</td></tr><tr><td><strong>Assistant</strong></td><td><code>total - system - user - tools</code></td><td>KI-Textausgabe + Reasoning-Token</td></tr></tbody></table><p><strong>Checkpoint ✅</strong>: Bestätigen Sie, dass Sie die Token-Anteile und -Mengen für jede Kategorie sehen.</p><h3 id="schritt-3-kumulierte-bereinigungsstatistiken-anzeigen" tabindex="-1">Schritt 3: Kumulierte Bereinigungsstatistiken anzeigen <a class="header-anchor" href="#schritt-3-kumulierte-bereinigungsstatistiken-anzeigen" aria-label="Permalink to &quot;Schritt 3: Kumulierte Bereinigungsstatistiken anzeigen&quot;">​</a></h3><p>Geben Sie <code>/dcp stats</code> ein, um die historisch kumulierten Bereinigungseffekte anzuzeigen.</p><p><strong>Sie sollten sehen</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                    DCP Statistics                         │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Session:</span></span>
<span class="line"><span>────────────────────────────────────────────────────────────</span></span>
<span class="line"><span>  Tokens pruned: ~15.2K</span></span>
<span class="line"><span>  Tools pruned:   12</span></span>
<span class="line"><span></span></span>
<span class="line"><span>All-time:</span></span>
<span class="line"><span>────────────────────────────────────────────────────────────</span></span>
<span class="line"><span>  Tokens saved:  ~284.5K</span></span>
<span class="line"><span>  Tools pruned:   156</span></span>
<span class="line"><span>  Sessions:       8</span></span></code></pre></div><p><strong>Statistik-Erklärung</strong>:</p><ul><li><strong>Session</strong>: Bereinigungsdaten der aktuellen Sitzung (im Speicher)</li><li><strong>All-time</strong>: Kumulierte Daten aller historischen Sitzungen (auf Festplatte persistiert)</li></ul><p><strong>Checkpoint ✅</strong>: Bestätigen Sie, dass Sie die Bereinigungsstatistiken für die aktuelle Sitzung und die historische Gesamtsumme sehen.</p><h3 id="schritt-4-tools-manuell-bereinigen" tabindex="-1">Schritt 4: Tools manuell bereinigen <a class="header-anchor" href="#schritt-4-tools-manuell-bereinigen" aria-label="Permalink to &quot;Schritt 4: Tools manuell bereinigen&quot;">​</a></h3><p>Es gibt zwei Möglichkeiten, <code>/dcp sweep</code> zu verwenden:</p><h4 id="methode-1-alle-tools-seit-der-letzten-benutzernachricht-bereinigen" tabindex="-1">Methode 1: Alle Tools seit der letzten Benutzernachricht bereinigen <a class="header-anchor" href="#methode-1-alle-tools-seit-der-letzten-benutzernachricht-bereinigen" aria-label="Permalink to &quot;Methode 1: Alle Tools seit der letzten Benutzernachricht bereinigen&quot;">​</a></h4><p>Geben Sie <code>/dcp sweep</code> (ohne Parameter) ein.</p><p><strong>Sie sollten sehen</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                      DCP Sweep                            │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Swept 8 tool(s) since previous user message.</span></span>
<span class="line"><span>Tokens saved: ~12,345</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  • Read: src/config.ts</span></span>
<span class="line"><span>  • Read: src/utils.ts</span></span>
<span class="line"><span>  • Bash: npm test</span></span>
<span class="line"><span>  • Read: package.json</span></span>
<span class="line"><span>  • Read: src/index.ts</span></span>
<span class="line"><span>  • Bash: git status</span></span>
<span class="line"><span>  • Read: README.md</span></span>
<span class="line"><span>  • Write: docs/tutorial.md</span></span></code></pre></div><h4 id="methode-2-die-letzten-n-tools-bereinigen" tabindex="-1">Methode 2: Die letzten N Tools bereinigen <a class="header-anchor" href="#methode-2-die-letzten-n-tools-bereinigen" aria-label="Permalink to &quot;Methode 2: Die letzten N Tools bereinigen&quot;">​</a></h4><p>Geben Sie <code>/dcp sweep 5</code> ein, um die letzten 5 Tools zu bereinigen.</p><p><strong>Sie sollten sehen</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>╭───────────────────────────────────────────────────────────╮</span></span>
<span class="line"><span>│                      DCP Sweep                            │</span></span>
<span class="line"><span>╰───────────────────────────────────────────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Swept last 5 tool(s).</span></span>
<span class="line"><span>Tokens saved: ~7,892</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  • Read: src/index.ts</span></span>
<span class="line"><span>  • Bash: git status</span></span>
<span class="line"><span>  • Read: README.md</span></span>
<span class="line"><span>  • Write: docs/tutorial.md</span></span>
<span class="line"><span>  • Bash: npm run build</span></span></code></pre></div><p><strong>Hinweis zu geschützten Tools</strong>:</p><p>Wenn geschützte Tools übersprungen wurden, zeigt die Ausgabe:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Swept 5 tool(s).</span></span>
<span class="line"><span>Tokens saved: ~7,892</span></span>
<span class="line"><span>(2 protected tool(s) skipped)</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Geschützte Tools (wie <code>write</code>, <code>edit</code>) und geschützte Dateipfade werden automatisch übersprungen und nicht bereinigt.</p></div><p><strong>Checkpoint ✅</strong>: Bestätigen Sie, dass Sie die Liste der bereinigten Tools und die Anzahl der eingesparten Token sehen.</p><h3 id="schritt-5-bereinigungseffekte-erneut-uberprufen" tabindex="-1">Schritt 5: Bereinigungseffekte erneut überprüfen <a class="header-anchor" href="#schritt-5-bereinigungseffekte-erneut-uberprufen" aria-label="Permalink to &quot;Schritt 5: Bereinigungseffekte erneut überprüfen&quot;">​</a></h3><p>Geben Sie nach der Bereinigung erneut <code>/dcp context</code> ein, um die neue Token-Verteilung anzuzeigen.</p><p><strong>Sie sollten sehen</strong>:</p><ul><li>Der Anteil der <code>Tools</code>-Kategorie ist gesunken</li><li>Die <code>Summary</code> zeigt eine erhöhte Anzahl bereinigter Tools</li><li>Die <code>Current context</code>-Gesamtzahl ist gesunken</li></ul><p><strong>Checkpoint ✅</strong>: Bestätigen Sie, dass die Token-Nutzung deutlich gesunken ist.</p><h2 id="haufige-fehler-vermeiden" tabindex="-1">Häufige Fehler vermeiden <a class="header-anchor" href="#haufige-fehler-vermeiden" aria-label="Permalink to &quot;Häufige Fehler vermeiden&quot;">​</a></h2><h3 id="❌-fehler-wichtige-tools-versehentlich-loschen" tabindex="-1">❌ Fehler: Wichtige Tools versehentlich löschen <a class="header-anchor" href="#❌-fehler-wichtige-tools-versehentlich-loschen" aria-label="Permalink to &quot;❌ Fehler: Wichtige Tools versehentlich löschen&quot;">​</a></h3><p><strong>Szenario</strong>: Sie haben gerade mit dem <code>write</code>-Tool eine wichtige Datei erstellt und führen dann <code>/dcp sweep</code> aus.</p><p><strong>Falsches Ergebnis</strong>: Das <code>write</code>-Tool wird bereinigt, und die KI weiß möglicherweise nicht, dass die Datei erstellt wurde.</p><p><strong>Richtige Vorgehensweise</strong>:</p><ul><li><code>write</code>, <code>edit</code> und ähnliche Tools sind standardmäßig geschützt</li><li>Ändern Sie die <code>protectedTools</code>-Konfiguration nicht manuell, um diese Tools zu entfernen</li><li>Warten Sie nach Abschluss kritischer Aufgaben einige Runden, bevor Sie bereinigen</li></ul><h3 id="❌-fehler-falscher-bereinigungszeitpunkt" tabindex="-1">❌ Fehler: Falscher Bereinigungszeitpunkt <a class="header-anchor" href="#❌-fehler-falscher-bereinigungszeitpunkt" aria-label="Permalink to &quot;❌ Fehler: Falscher Bereinigungszeitpunkt&quot;">​</a></h3><p><strong>Szenario</strong>: Das Gespräch hat gerade begonnen, es gibt nur wenige Tool-Aufrufe, und Sie führen <code>/dcp sweep</code> aus.</p><p><strong>Falsches Ergebnis</strong>: Es werden nur wenige Token eingespart, und die Kontextkohärenz könnte beeinträchtigt werden.</p><p><strong>Richtige Vorgehensweise</strong>:</p><ul><li>Warten Sie, bis das Gespräch einen gewissen Umfang erreicht hat (z.B. 10+ Tool-Aufrufe), bevor Sie bereinigen</li><li>Bereinigen Sie Tool-Ausgaben der vorherigen Runde, bevor Sie eine neue Aufgabe beginnen</li><li>Verwenden Sie <code>/dcp context</code>, um zu beurteilen, ob eine Bereinigung sinnvoll ist</li></ul><h3 id="❌-fehler-ubermaßige-abhangigkeit-von-manueller-bereinigung" tabindex="-1">❌ Fehler: Übermäßige Abhängigkeit von manueller Bereinigung <a class="header-anchor" href="#❌-fehler-ubermaßige-abhangigkeit-von-manueller-bereinigung" aria-label="Permalink to &quot;❌ Fehler: Übermäßige Abhängigkeit von manueller Bereinigung&quot;">​</a></h3><p><strong>Szenario</strong>: Sie führen bei jedem Gespräch manuell <code>/dcp sweep</code> aus.</p><p><strong>Falsches Ergebnis</strong>:</p><ul><li>Automatische Bereinigungsstrategien (Deduplizierung, Überschreiben, Fehlerbereinigung) werden verschwendet</li><li>Erhöhter Arbeitsaufwand</li></ul><p><strong>Richtige Vorgehensweise</strong>:</p><ul><li>Aktivieren Sie standardmäßig automatische Bereinigungsstrategien (Konfiguration: <code>strategies.*.enabled</code>)</li><li>Verwenden Sie manuelle Bereinigung als Ergänzung, wenn nötig</li><li>Überprüfen Sie die Effekte der automatischen Bereinigung mit <code>/dcp stats</code></li></ul><h2 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h2><p>Die 4 DCP-Befehle helfen Ihnen, die Token-Nutzung zu überwachen und zu steuern:</p><table tabindex="0"><thead><tr><th>Befehl</th><th>Kernfunktion</th></tr></thead><tbody><tr><td><code>/dcp</code></td><td>Hilfeinformationen anzeigen</td></tr><tr><td><code>/dcp context</code></td><td>Token-Verteilung der aktuellen Sitzung analysieren</td></tr><tr><td><code>/dcp stats</code></td><td>Kumulierte Bereinigungsstatistiken anzeigen</td></tr><tr><td><code>/dcp sweep [n]</code></td><td>Tools manuell bereinigen</td></tr></tbody></table><p><strong>Token-Berechnungsstrategie</strong>:</p><ul><li>System: System-Prompt (aus der ersten Antwort abgeleitet)</li><li>Tools: Tool-Ein- und -Ausgaben (abzüglich bereinigter Teile)</li><li>User: Alle Benutzernachrichten (geschätzt)</li><li>Assistant: KI-Ausgabe + Reasoning-Token (Residuum)</li></ul><p><strong>Schutzmechanismus</strong>:</p><ul><li>Geschützte Tools: <code>task</code>, <code>todowrite</code>, <code>todoread</code>, <code>discard</code>, <code>extract</code>, <code>batch</code>, <code>write</code>, <code>edit</code>, <code>plan_enter</code>, <code>plan_exit</code></li><li>Geschützte Dateien: Konfigurierte Glob-Muster</li><li>Alle Bereinigungsoperationen überspringen diese Inhalte automatisch</li></ul><p><strong>Best Practices</strong>:</p><ul><li>Überprüfen Sie regelmäßig <code>/dcp context</code>, um die Token-Zusammensetzung zu verstehen</li><li>Führen Sie <code>/dcp sweep</code> vor neuen Aufgaben aus, um den Verlauf zu bereinigen</li><li>Verlassen Sie sich auf automatische Bereinigung, manuelle Bereinigung als Ergänzung</li><li>Überprüfen Sie Langzeiteffekte mit <code>/dcp stats</code></li></ul><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir den <strong><a href="./../../advanced/protection/">Schutzmechanismus</a></strong>.</p><p>Sie werden lernen:</p><ul><li>Wie der Rundenschutz versehentliche Bereinigung verhindert</li><li>Wie Sie die Liste der geschützten Tools anpassen</li><li>Wie Sie geschützte Dateimuster konfigurieren</li><li>Spezielle Behandlung von Sub-Agent-Sitzungen</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie hier, um die Quellcode-Positionen anzuzeigen</strong></summary><blockquote><p>Aktualisiert: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeile</th></tr></thead><tbody><tr><td>/dcp Hilfebefehl</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/help.ts" target="_blank" rel="noreferrer"><code>lib/commands/help.ts</code></a></td><td>19-32</td></tr><tr><td>/dcp context Befehl</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/context.ts" target="_blank" rel="noreferrer"><code>lib/commands/context.ts</code></a></td><td>238-247</td></tr><tr><td>Token-Berechnungsstrategie</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/context.ts" target="_blank" rel="noreferrer"><code>lib/commands/context.ts</code></a></td><td>5-38</td></tr><tr><td>/dcp stats Befehl</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/stats.ts" target="_blank" rel="noreferrer"><code>lib/commands/stats.ts</code></a></td><td>46-67</td></tr><tr><td>/dcp sweep Befehl</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/commands/sweep.ts" target="_blank" rel="noreferrer"><code>lib/commands/sweep.ts</code></a></td><td>123-259</td></tr><tr><td>Konfiguration geschützter Tools</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/lib/config.ts" target="_blank" rel="noreferrer"><code>lib/config.ts</code></a></td><td>461</td></tr><tr><td>Standard-Liste geschützter Tools</td><td><a href="https://github.com/Opencode-DCP/opencode-dynamic-context-pruning/blob/main/README.md" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>150-151</td></tr></tbody></table><p><strong>Wichtige Konstanten</strong>:</p><ul><li><code>DEFAULT_PROTECTED_TOOLS</code>: Standard-Liste der geschützten Tools</li></ul><p><strong>Wichtige Funktionen</strong>:</p><ul><li><code>handleHelpCommand()</code>: Verarbeitet den /dcp Hilfebefehl</li><li><code>handleContextCommand()</code>: Verarbeitet den /dcp context Befehl</li><li><code>analyzeTokens()</code>: Berechnet die Token-Anzahl für jede Kategorie</li><li><code>handleStatsCommand()</code>: Verarbeitet den /dcp stats Befehl</li><li><code>handleSweepCommand()</code>: Verarbeitet den /dcp sweep Befehl</li><li><code>buildToolIdList()</code>: Erstellt die Tool-ID-Liste</li></ul></details>`,88)])])}const g=n(a,[["render",r]]);export{h as __pageData,g as default};
